    {"language": "typescript", "framework": "fastify",
     "tradeoff": "Faster iteration; GC pauses risk p99 budget."}
  ],
  "adrStub": {
    "status": "proposed",
    "context": "4-person team, price-feed service, 30ms p99 budget, 24mo horizon.",
    "decision": "Go + Echo.",
